<span class="line"><span style="color:#9399B2;">        (</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">total_input_tokens</span><span style="color:#9399B2;">()</span><span style="color:#CBA6F7;"> as</span><span style="color:#CBA6F7;"> f32</span><span style="color:#94E2D5;"> /</span><span style="color:#CDD6F4;"> available</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> *</span><span style="color:#FAB387;"> 100</span><span style="color:#9399B2;">.</span><span style="color:#FAB387;">0</span></span>
